package com.example.carstore.controller;
import com.example.carstore.entity.Promotion;import com.example.carstore.service.PromotionService;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/promotions") public class RestPromotionController{private final PromotionService s;public RestPromotionController(PromotionService s){this.s=s;}private boolean admin(Authentication a){return a!=null&&a.getAuthorities().stream().anyMatch(x->"ROLE_ADMIN".equals(x.getAuthority()));}@GetMapping public Map<String,Object> active(){return Map.of("success",true,"data",s.active());}@GetMapping("/car/{carId}")public Map<String,Object> byCar(@PathVariable Integer carId){return Map.of("success",true,"data",s.activeForCar(carId));}@GetMapping("/admin")public Map<String,Object> all(Authentication a){if(!admin(a))throw new IllegalArgumentException("Không có quyền.");return Map.of("success",true,"data",s.all());}@PostMapping public Map<String,Object> create(@RequestBody Promotion p,Authentication a){if(!admin(a))throw new IllegalArgumentException("Không có quyền.");return Map.of("success",true,"data",s.save(p));}@PutMapping("/{id}")public Map<String,Object> update(@PathVariable Integer id,@RequestBody Promotion p,Authentication a){if(!admin(a))throw new IllegalArgumentException("Không có quyền.");p.setId(id);return Map.of("success",true,"data",s.save(p));}@PostMapping("/{id}/cars/{carId}")public Map<String,Object> apply(@PathVariable Integer id,@PathVariable Integer carId,Authentication a){if(!admin(a))throw new IllegalArgumentException("Không có quyền.");s.applyToCar(id,carId);return Map.of("success",true);}@DeleteMapping("/{id}/cars/{carId}")public Map<String,Object> remove(@PathVariable Integer id,@PathVariable Integer carId,Authentication a){if(!admin(a))throw new IllegalArgumentException("Không có quyền.");s.removeFromCar(id,carId);return Map.of("success",true);}@DeleteMapping("/{id}")public Map<String,Object> delete(@PathVariable Integer id,Authentication a){if(!admin(a))throw new IllegalArgumentException("Không có quyền.");s.delete(id);return Map.of("success",true);}}
